const clients=$("Fetch Clients").all().map(function(i){return i.json;}).filter(function(j){return j&&Object.keys(j).length>0;});
const admins=$("Fetch Admins").all().map(function(i){return i.json||{};});
function norm(p){var d=String(p||"").replace(/[^0-9]/g,"");if(d.length>10)d=d.slice(-10);return d;}
var ap=admins.length?norm(admins[0].phoneLast10||admins[0].phone):"9601775061"; if(ap.length===10) ap="91"+ap;
var now=new Date();
var y=now.getUTCFullYear(); var mo=now.getUTCMonth()+1; var mm=(mo<10?"0":"")+mo;
var monStart=y+"-"+mm+"-01"; var monEnd=y+"-"+mm+"-31";
var today=now.toISOString().slice(0,10);
var in30=new Date(now.getTime()+30*86400000).toISOString().slice(0,10);
var mat=[]; var ren=[];
clients.forEach(function(c){
  var md=String(c.maturityDate||"").slice(0,10);
  if(md>=monStart && md<=monEnd) mat.push(c);
  var fd=String(c.fupDate||"").slice(0,10);
  if(fd && fd>=today && fd<=in30) ren.push(c);
});
ren.sort(function(a,b){return String(a.fupDate).localeCompare(String(b.fupDate));});
mat.sort(function(a,b){return String(a.maturityDate).localeCompare(String(b.maturityDate));});
var matLines=mat.slice(0,20).map(function(c){return "- "+c.name+" ("+norm(c.phone||c.phoneLast10)+") - "+String(c.maturityDate).slice(0,10)+" - Rs "+(c.sumAssured||0);});
var renLines=ren.slice(0,20).map(function(c){return "- "+c.name+" ("+norm(c.phone||c.phoneLast10)+") - due "+String(c.fupDate).slice(0,10)+" - Rs "+(c.premium||0);});
var text="📋 Policy Lifecycle (aaje):\n\n💰 Maturities this month: "+mat.length+"\n"+(matLines.join("\n")||"-")+"\n\n🔁 Renewals due (30 din): "+ren.length+"\n"+(renLines.join("\n")||"-")+"\n\nRenewal CSV lifecycle_log ma save thai.";
var csv="name,policyNo,fupDate,premium,phone\n"+ren.map(function(c){return [c.name,c.policyNo,String(c.fupDate).slice(0,10),(c.premium||0),norm(c.phone||c.phoneLast10)].join(",");}).join("\n");
return [{ json: { phone:ap, text:text, purpose:"policy_lifecycle", maturityCount:mat.length, renewalCount:ren.length, csv:csv, runDate:today } }];

// Expand one composed admin message into one item per opted-in admin.
// Kept separate from 'Build & Notify' so its other branches still see a single item.
const msg = $('Build & Notify').first().json || {};
let admins = [];
try { admins = $('Fetch Admins').all().map(function (i) { return i.json || {}; }); } catch (e) { admins = []; }
function norm(p) { return String(p || '').replace(/[^0-9]/g, '').slice(-10); }

const seen = {};
const out = [];
for (const a of admins) {
  if (!a || a.isActive === false || a.active === false) continue;
  if (a.notifyEnquiries !== true) continue;   // admins opt in; the rest keep their rights
  const p = norm(a.phoneLast10 || a.phone || a.phoneNumber);
  if (p.length !== 10 || seen[p]) continue;
  seen[p] = true;
  out.push({ json: Object.assign({}, msg, { phone: '91' + p, adminName: a.name || '' }) });
}
if (!out.length) out.push({ json: Object.assign({}, msg, { phone: '919601775061', adminName: 'CGPE Admin' }) });
return out;
